using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;

namespace YourNamespace.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class FileUploadController : ControllerBase
    {
        private const string UploadDirectory = "wwwroot/uploads";

        [HttpPost("avatar")]
        public IActionResult UploadAvatar(IFormFile file)
        {
            if (file == null || file.Length == 0) return BadRequest();

            var fileName = Path.GetFileName(file.FileName);
            var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

            var allowedExtensions = new[] { ".jpg", ".jpeg", ".png", ".bmp", ".pdf", ".doc", ".docx", ".xls", ".xlsx" };
            if (!allowedExtensions.Contains(extension)) return BadRequest("Invalid file type");

            var uploadPath = Path.Combine(UploadDirectory, fileName);
            using (var stream = new FileStream(uploadPath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok($"https://{Request.Host}/{uploadPath}");
        }

        [HttpPost("document")]
